"use client";

import { useEffect, useState } from "react";
import { getAccessToken } from "@/lib/auth";

type AuthStatus = "checking" | "authed" | "unauthed";

/**
 * Client-only auth snapshot after mount. Use for gating dashboard UI;
 * first paint is `checking` until `useEffect` runs.
 */
export function useAuth() {
  const [status, setStatus] = useState<AuthStatus>("checking");

  useEffect(() => {
    setStatus(getAccessToken() ? "authed" : "unauthed");
  }, []);

  return {
    status,
    isAuthenticated: status === "authed",
    isUnauthenticated: status === "unauthed",
    isChecking: status === "checking"
  };
}

"use client";

import { useRouter } from "next/navigation";
import { useEffect } from "react";
import { useAuth } from "@/hooks/useAuth";

/** Wrap dashboard routes: require stored access token, else redirect to login. */
export function ProtectedLayout({ children }: { children: React.ReactNode }) {
  const router = useRouter();
  const { isChecking, isUnauthenticated } = useAuth();

  useEffect(() => {
    if (!isChecking && isUnauthenticated) {
      router.replace("/login");
    }
  }, [isChecking, isUnauthenticated, router]);

  if (isChecking || isUnauthenticated) {
    return (
      <div className="flex min-h-screen items-center justify-center text-sm text-muted-foreground">
        Checking session…
      </div>
    );
  }

  return <>{children}</>;
}

import Link from "next/link";
import { buttonVariants } from "@/components/ui/Button";
import { LogoutButton } from "@/components/layout/LogoutButton";
import { cn } from "@/lib/utils";

const links = [
  { href: "/programs", label: "Programs" },
  { href: "/programs/new", label: "New program" },
  { href: "/import", label: "CSV import" },
  { href: "/audit", label: "Audit log" }
] as const;

export function Navbar() {
  return (
    <nav className="flex flex-wrap items-center gap-2 border-b bg-card px-4 py-3">
      <Link
        href="/programs"
        className={cn(buttonVariants({ variant: "ghost", size: "sm" }), "mr-2 px-2 font-semibold")}
      >
        Wellspring Admin
      </Link>
      {links.map((l) => (
        <Link
          key={l.href}
          href={l.href}
          className={cn(buttonVariants({ variant: "ghost", size: "sm" }))}
        >
          {l.label}
        </Link>
      ))}
      <div className="ml-auto">
        <LogoutButton />
      </div>
    </nav>
  );
}

